import { View } from 'react-native';
import { type useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { MessageCard } from '../duels-primitives';
import { type UseKangurMobileDuelLobbyChatResult as DuelChatState } from '../useKangurMobileDuelLobbyChat';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];

export function ChatStatus({ chat, copy }: { chat: DuelChatState; copy: DuelCopy }): React.JSX.Element | null {
  if (chat.error !== null) {
    return (
      <MessageCard
        title={copy({
          de: 'Lobby-Chat konnte nicht geladen werden',
          en: 'Could not load the lobby chat',
          pl: 'Nie udało się pobrać czatu lobby',
        })}
        description={chat.error}
        tone='error'
      />
    );
  }
  if (chat.isLoading) {
    return (
      <MessageCard
        title={copy({
          de: 'Lobby-Chat wird geladen',
          en: 'Loading lobby chat',
          pl: 'Ładujemy czat lobby',
        })}
        description={chat.isRestoringAuth
            ? copy({
                de: 'Die Anmeldung wird wiederhergestellt und die letzten Nachrichten werden geladen.',
                en: 'Restoring sign-in and loading the latest messages.',
                pl: 'Przywracamy logowanie i pobieramy ostatnie wiadomości.',
              })
            : copy({
                de: 'Die aktuellen Nachrichten aus der Lobby werden geladen.',
                en: 'Loading the latest messages from the lobby.',
                pl: 'Pobieramy bieżące wiadomości z lobby.',
              })}
      />
    );
  }
  return null;
}

import { Text, View } from 'react-native';
import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { KangurMobileCard as Card, KangurMobileFilterChip } from '../shared/KangurMobileUi';
import { ActionButton, AutoRefreshChip, LobbyEntryCard, MessageCard } from './duels-primitives';
import { type KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';
import { type DuelModeFilterOption, MODE_FILTER_OPTIONS, formatModeLabel, formatOperationLabel, formatStatusLabel, localizeDuelText } from './utils/duels-ui';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];
type PublicEntry = KangurDuelLobbyEntry;
type InviteEntry = KangurDuelLobbyEntry;

type DuelLobbyRoomsPanelProps = {
  autoRefreshChipLabel: string;
  autoRefreshEnabled: boolean;
  copy: DuelCopy;
  lobby: DuelLobbyState;
  locale: DuelLocale;
  onToggleAutoRefresh: () => void;
  renderJoinAction: (targetSessionId: string) => React.JSX.Element;
  renderSpectateAction: (targetSessionId: string) => React.JSX.Element;
};

const LobbyHeader = ({ copy, lobby, autoRefreshEnabled, autoRefreshChipLabel, onToggleAutoRefresh }: Pick<DuelLobbyRoomsPanelProps, 'copy' | 'lobby' | 'autoRefreshEnabled' | 'autoRefreshChipLabel' | 'onToggleAutoRefresh'>): React.JSX.Element => (
  <View style={{ gap: 12 }}>
    <View style={{ gap: 4 }}>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>{copy({ de: 'Lobby', en: 'Lobby', pl: 'Lobby' })}</Text>
      <Text style={{ color: '#64748b', fontSize: 13 }}>{copy({ de: `Sichtbare öffentliche Räume: ${lobby.visiblePublicEntries.length}`, en: `Visible public rooms: ${lobby.visiblePublicEntries.length}`, pl: `Widoczne publiczne pokoje: ${lobby.visiblePublicEntries.length}` })}</Text>
    </View>
    <View style={{ gap: 8, alignItems: 'stretch' }}>
      <ActionButton disabled={lobby.isActionPending} label={copy({ de: 'Aktualisieren', en: 'Refresh', pl: 'Odśwież' })} onPress={lobby.refresh} stretch tone='secondary' />
      <AutoRefreshChip enabled={autoRefreshEnabled} label={autoRefreshChipLabel} onToggle={onToggleAutoRefresh} fullWidth />
    </View>
  </View>
);

const InviteEntriesList = ({ lobby, renderJoinAction, locale, copy }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'renderJoinAction' | 'locale' | 'copy'>): React.JSX.Element => (
  <View style={{ gap: 10 }}>
    <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{copy({ de: 'Einladungen', en: 'Invites', pl: 'Zaproszenia' })}</Text>
    {lobby.inviteEntries.map((entry: InviteEntry) => (
      <LobbyEntryCard key={entry.sessionId} action={renderJoinAction(entry.sessionId)} actionLabel={copy({ de: 'Private Einladung für angemeldete Lernende.', en: 'Private invite for a signed-in learner.', pl: 'Prywatne zaproszenie dla zalogowanego ucznia.' })} description={copy({ de: `Gastgeber ${entry.host.displayName} lädt zu einem privaten Duell ${formatOperationLabel(entry.operation, locale)} ein.`, en: `Host ${entry.host.displayName} is inviting you to a private ${formatOperationLabel(entry.operation, locale)} duel.`, pl: `Gospodarz ${entry.host.displayName} zaprasza do prywatnego pojedynku ${formatOperationLabel(entry.operation, locale)}.` })} entry={entry} locale={locale} />
    ))}
  </View>
);

const PublicEntryRow = ({ entry, renderJoinAction, renderSpectateAction, locale, copy }: { entry: PublicEntry; renderJoinAction: (sessionId: string) => React.JSX.Element; renderSpectateAction: (sessionId: string) => React.JSX.Element; locale: DuelLocale; copy: DuelCopy }): React.JSX.Element => {
  const modeLabel = formatModeLabel(entry.mode, locale);
  const statusLabel = formatStatusLabel(entry.status, locale).toLowerCase();
  const desc = copy({ de: `${modeLabel} von ${entry.host.displayName}. Status: ${statusLabel}.`, en: `${modeLabel} hosted by ${entry.host.displayName}. Status: ${statusLabel}.`, pl: `${modeLabel} gospodarza ${entry.host.displayName}. Status: ${statusLabel}.` });
  return (
    <LobbyEntryCard action={<View style={{ gap: 8 }}>{renderJoinAction(entry.sessionId)}{renderSpectateAction(entry.sessionId)}</View>} actionLabel={copy({ de: 'Du kannst als Spieler beitreten oder den Raum im Zuschauermodus öffnen.', en: 'You can join as a player or open the room in spectator mode.', pl: 'Możesz dołączyć jako gracz albo otworzyć pokój w trybie obserwatora.' })} description={desc} entry={entry} locale={locale} />
  );
};

const PublicEntriesList = ({ lobby, renderJoinAction, renderSpectateAction, locale, copy }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'renderJoinAction' | 'renderSpectateAction' | 'locale' | 'copy'>): React.JSX.Element => lobby.visiblePublicEntries.length === 0 ? (
  <MessageCard title={copy({ de: 'Keine öffentlichen Duelle', en: 'No public duels', pl: 'Brak publicznych pojedynków' })} description={copy({ de: 'Ein anderer Filter oder ein schnelles Match erstellt einen neuen Raum zum Beitreten.', en: 'Changing the filter or starting a quick match will create a new room to join.', pl: 'Zmiana filtra albo szybki mecz utworzy nowy pokój gotowy do dołączenia.' })} />
) : (
  <View style={{ gap: 10 }}>
    <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{copy({ de: 'Öffentliche Räume', en: 'Public rooms', pl: 'Publiczne pokoje' })}</Text>
    {lobby.visiblePublicEntries.map((entry: PublicEntry) => <PublicEntryRow key={entry.sessionId} copy={copy} entry={entry} locale={locale} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />)}
  </View>
);

const RoomsContent = ({ lobby, copy, locale, renderJoinAction, renderSpectateAction }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'copy' | 'locale' | 'renderJoinAction' | 'renderSpectateAction'>): React.JSX.Element => (
  <>
    {lobby.inviteEntries.length > 0 && <InviteEntriesList copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} />}
    <PublicEntriesList copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />
  </>
);

export function DuelLobbyRoomsPanel({ autoRefreshChipLabel, autoRefreshEnabled, copy, lobby, locale, onToggleAutoRefresh, renderJoinAction, renderSpectateAction }: DuelLobbyRoomsPanelProps): React.JSX.Element {
  const renderLobbyStatus = (currentLobby: DuelLobbyState): React.JSX.Element | null => {
    if (currentLobby.lobbyError !== null) return <MessageCard title={copy({ de: 'Lobby ist nicht verfügbar', en: 'Lobby is unavailable', pl: 'Lobby jest niedostępne' })} description={currentLobby.lobbyError} tone='error' />;
    if (currentLobby.isLobbyLoading) return <MessageCard title={copy({ de: 'Lobby wird geladen', en: 'Loading lobby', pl: 'Ładujemy lobby' })} description={currentLobby.isRestoringAuth ? copy({ de: 'Die Anmeldung wird wiederhergestellt und verfügbare Duelle werden geladen.', en: 'Restoring sign-in and loading available duels.', pl: 'Przywracamy logowanie i pobieramy dostępne pojedynki.' }) : copy({ de: 'Verfügbare öffentliche und private Räume werden geladen.', en: 'Loading available public and private rooms.', pl: 'Pobieramy dostępne publiczne i prywatne pokoje.' })} />;
    return null;
  };

  const status = renderLobbyStatus(lobby);
  return (
    <Card>
      <LobbyHeader autoRefreshChipLabel={autoRefreshChipLabel} autoRefreshEnabled={autoRefreshEnabled} copy={copy} lobby={lobby} onToggleAutoRefresh={onToggleAutoRefresh} />
      <View style={{ flexDirection: 'column', gap: 8 }}>
        {MODE_FILTER_OPTIONS.map((option: DuelModeFilterOption) => (
          <KangurMobileFilterChip
            fullWidth
            key={option.value}
            label={localizeDuelText(option.label, locale)}
            onPress={() => lobby.setModeFilter(option.value as DuelModeFilterOption['value'])}
            selected={lobby.modeFilter === option.value}
          />
        ))}
      </View>
      {status ?? <RoomsContent copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />}
    </Card>
  );
}

import { Text, TextInput, View } from 'react-native';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  KangurMobileCard as Card,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import { ActionButton, MessageCard } from './duels-primitives';
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];

type DuelLobbySearchSectionProps = {
  copy: DuelCopy;
  lobby: DuelLobbyState;
  onOpenSession: (sessionId: string) => void;
  searchStatusLabel: string;
  searchStatusTone: Tone;
};

function SearchResultRow({
  entry,
  copy,
  isActionPending,
  onOpenSession,
  createPrivateChallenge,
}: {
  entry: DuelLobbyState['searchResults'][number];
  copy: DuelCopy;
  isActionPending: boolean;
  onOpenSession: (sessionId: string) => void;
  createPrivateChallenge: DuelLobbyState['createPrivateChallenge'];
}): React.JSX.Element {
  return (
    <View
      style={{
        borderRadius: 20,
        borderWidth: 1,
        borderColor: '#e2e8f0',
        backgroundColor: '#f8fafc',
        padding: 14,
        gap: 8,
        alignSelf: 'stretch',
        width: '100%',
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {entry.displayName}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12 }}>
        {copy({
          de: `Login: ${entry.loginName}`,
          en: `Login: ${entry.loginName}`,
          pl: `Login: ${entry.loginName}`,
        })}
      </Text>
      <ActionButton
        disabled={isActionPending}
        label={copy({
          de: 'Private Herausforderung senden',
          en: 'Send private challenge',
          pl: 'Wyślij prywatne wyzwanie',
        })}
        onPress={async () => {
          const nextSessionId = await createPrivateChallenge(entry.learnerId);
          if (nextSessionId !== null) {
            onOpenSession(nextSessionId);
          }
        }}
        stretch
      />
    </View>
  );
}

function SearchResultsList({
  lobby,
  copy,
  onOpenSession,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
  onOpenSession: (sessionId: string) => void;
}): React.JSX.Element | null {
  if (lobby.searchError !== null) {
    return (
      <MessageCard
        title={copy({
          de: 'Suche fehlgeschlagen',
          en: 'Search failed',
          pl: 'Wyszukiwanie nie powiodło się',
        })}
        description={lobby.searchError}
        tone='error'
      />
    );
  }

  if (lobby.isSearchLoading) {
    return (
      <MessageCard
        title={copy({
          de: 'Lernende werden gesucht',
          en: 'Searching learners',
          pl: 'Szukamy uczniów',
        })}
        description={copy({
          de: 'Die Ergebnisse für die eingegebene Anfrage werden abgeglichen.',
          en: 'Matching results for the entered query.',
          pl: 'Dopasowujemy wyniki dla wpisanego zapytania.',
        })}
      />
    );
  }

  if (
    lobby.searchSubmittedQuery !== '' &&
    lobby.searchSubmittedQuery.length >= 2 &&
    lobby.searchResults.length === 0
  ) {
    return (
      <MessageCard
        title={copy({
          de: 'Keine Ergebnisse',
          en: 'No results',
          pl: 'Brak wyników',
        })}
        description={copy({
          de: 'Es wurden keine Lernenden gefunden, die zur eingegebenen Anfrage passen.',
          en: 'We did not find any learners matching the entered query.',
          pl: 'Nie znaleźliśmy uczniów pasujących do wpisanego zapytania.',
        })}
      />
    );
  }

  if (lobby.searchResults.length > 0) {
    return (
      <View style={{ gap: 10 }}>
        {lobby.searchResults.map((entry) => (
          <SearchResultRow
            key={entry.learnerId}
            copy={copy}
            createPrivateChallenge={lobby.createPrivateChallenge}
            entry={entry}
            isActionPending={lobby.isActionPending}
            onOpenSession={onOpenSession}
          />
        ))}
      </View>
    );
  }

  return null;
}

function SearchInputArea({
  lobby,
  copy,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
}): React.JSX.Element {
  return (
    <View style={{ gap: 8, alignSelf: 'stretch' }}>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Gib mindestens 2 Zeichen des Logins oder Namens des Lernenden ein.',
          en: 'Enter at least 2 characters from the learner login or name.',
          pl: 'Wpisz co najmniej 2 znaki loginu lub nazwy ucznia.',
        })}
      </Text>
      <TextInput
        accessibilityLabel={copy({
          de: 'Lernendensuche',
          en: 'Learner search',
          pl: 'Wyszukiwarka uczniów',
        })}
        onChangeText={lobby.setSearchQuery}
        placeholder={copy({
          de: 'Lernenden suchen',
          en: 'Search learner',
          pl: 'Szukaj ucznia',
        })}
        style={{
          backgroundColor: '#ffffff',
          borderColor: '#cbd5e1',
          borderRadius: 16,
          borderWidth: 1,
          paddingHorizontal: 14,
          paddingVertical: 12,
          width: '100%',
        }}
        value={lobby.searchQuery}
      />
    </View>
  );
}

function SearchActionButtons({
  lobby,
  copy,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
}): React.JSX.Element {
  return (
    <View style={{ gap: 8 }}>
      <ActionButton
        disabled={lobby.searchQuery.trim().length < 2}
        label={copy({
          de: 'Suchen',
          en: 'Search',
          pl: 'Szukaj',
        })}
        onPress={lobby.submitSearch}
        stretch
      />
      {lobby.searchSubmittedQuery !== '' ? (
        <ActionButton
          label={copy({
            de: 'Suche löschen',
            en: 'Clear search',
            pl: 'Wyczyść wyszukiwanie',
          })}
          onPress={lobby.clearSearch}
          stretch
          tone='secondary'
        />
      ) : null}
    </View>
  );
}

function SearchForm({
  lobby,
  copy,
  onOpenSession,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
  onOpenSession: (sessionId: string) => void;
}): React.JSX.Element {
  return (
    <>
      <SearchInputArea copy={copy} lobby={lobby} />
      <SearchActionButtons copy={copy} lobby={lobby} />
      <SearchResultsList copy={copy} lobby={lobby} onOpenSession={onOpenSession} />
    </>
  );
}

export function DuelLobbySearchSection({
  copy,
  lobby,
  onOpenSession,
  searchStatusLabel,
  searchStatusTone,
}: DuelLobbySearchSectionProps): React.JSX.Element {
  return (
    <Card>
      <View style={{ gap: 8 }}>
        <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
          {copy({
            de: 'Lernende suchen',
            en: 'Search learners',
            pl: 'Szukaj uczniów',
          })}
        </Text>
        <Pill label={searchStatusLabel} tone={searchStatusTone} />
      </View>
      {!lobby.isAuthenticated ? (
        <MessageCard
          title={copy({
            de: 'Zum Suchen anmelden',
            en: 'Sign in to search learners',
            pl: 'Zaloguj się, aby szukać uczniów',
          })}
          description={copy({
            de: 'Nach der Anmeldung znajdziesz ucznia po loginie lub nazwie und od razu wyślesz prywatne wyzwanie.',
            en: 'After sign-in, you can find a learner by login or name and send a private challenge right away.',
            pl: 'Po zalogowaniu znajdziesz ucznia po loginie lub nazwie i od razu wyślesz prywatne wyzwanie.',
          })}
        />
      ) : (
        <SearchForm copy={copy} lobby={lobby} onOpenSession={onOpenSession} />
      )}
    </Card>
  );
}

import { Text, View } from 'react-native';
import type { 
  KangurDuelSession
} from '@kangur/contracts/kangur-duels';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  KangurMobileCard as Card,
  KangurMobilePill as Pill,
} from '../shared/KangurMobileUi';
import {
  MessageCard,
} from './duels-primitives';
import {
  formatDifficultyLabel,
  formatModeLabel,
  formatOperationLabel,
  formatQuestionProgress,
  formatRoundProgressLabel,
  formatSeriesTitle,
  formatSpectatorQuestionProgress,
  formatStatusLabel,
  getStatusTone,
} from './utils/duels-ui';
import { 
    type UseKangurMobileDuelSessionResult
} from './useKangurMobileDuelSession';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

export interface DuelSessionDetailsCardProps {
  copy: DuelCopy;
  duel: UseKangurMobileDuelSessionResult;
  hasWaitingSession: boolean;
  locale: DuelLocale;
  roundProgress: {
    total: number;
    completed: number;
    percentage: number;
    percent: number;
  } | null;
  sessionTimelineItems: string[];
}

function SessionTimeline({
  copy,
  items,
}: {
  copy: DuelCopy;
  items: string[];
}): React.JSX.Element {
  return (
    <View
      style={{
        borderRadius: 18,
        borderWidth: 1,
        borderColor: '#e2e8f0',
        backgroundColor: '#f8fafc',
        padding: 14,
        gap: 8,
      }}
    >
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {copy({
          de: 'Zeitachse der Sitzung',
          en: 'Session timeline',
          pl: 'Oś sesji',
        })}
      </Text>
      <View style={{ gap: 6 }}>
        {items.map((item) => (
          <Text
            key={item}
            style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}
          >
            {item}
          </Text>
        ))}
      </View>
    </View>
  );
}

function RoundProgressBar({
  locale,
  roundProgress,
  status,
}: {
  locale: DuelLocale;
  roundProgress: NonNullable<DuelSessionDetailsCardProps['roundProgress']>;
  status: string;
}): React.JSX.Element {
  const isFinished = status === 'completed' || status === 'aborted';
  return (
    <View style={{ gap: 6 }}>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {formatRoundProgressLabel(roundProgress, locale)}
      </Text>
      <View
        style={{
          height: 10,
          width: '100%',
          borderRadius: 999,
          backgroundColor: '#e2e8f0',
          overflow: 'hidden',
        }}
      >
        <View
          style={{
            height: '100%',
            width: `${roundProgress.percent}%`,
            borderRadius: 999,
            backgroundColor: isFinished ? '#16a34a' : '#1d4ed8',
          }}
        />
      </View>
    </View>
  );
}

function DetailsHeader({
  session,
  copy,
  locale,
}: {
  session: KangurDuelSession;
  copy: DuelCopy;
  locale: DuelLocale;
}): React.JSX.Element {
  let infoLabel = '';
  if (locale === 'de') {
    infoLabel = `${session.questionCount} Fragen · ${session.timePerQuestionSec}s pro Antwort · ${formatDifficultyLabel(session.difficulty, locale)}`;
  } else if (locale === 'en') {
    infoLabel = `${session.questionCount} questions · ${session.timePerQuestionSec}s per answer · ${formatDifficultyLabel(session.difficulty, locale)}`;
  } else {
    infoLabel = `${session.questionCount} pytań · ${session.timePerQuestionSec}s na odpowiedź · ${formatDifficultyLabel(session.difficulty, locale)}`;
  }
  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {copy({ de: `Sitzung ${session.id}`, en: `Session ${session.id}`, pl: `Sesja ${session.id}` })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
        {formatModeLabel(session.mode, locale)} · {formatOperationLabel(session.operation, locale)}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{infoLabel}</Text>
    </View>
  );
}

function ProgressPill({
  duel,
  session,
  locale,
}: {
  duel: UseKangurMobileDuelSessionResult;
  session: KangurDuelSession;
  locale: DuelLocale;
}): React.JSX.Element {
  return (
    <Pill
      label={
        duel.player
          ? formatQuestionProgress(session, duel.player, locale)
          : formatSpectatorQuestionProgress(session, locale)
      }
      tone={{ backgroundColor: '#eff6ff', borderColor: '#bfdbfe', textColor: '#1d4ed8' }}
    />
  );
}

function DetailsPills({
  duel,
  copy,
  locale,
}: {
  duel: UseKangurMobileDuelSessionResult;
  copy: DuelCopy;
  locale: DuelLocale;
}): React.JSX.Element {
  const session = duel.session;
  if (!session) return <></>;
  return (
    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
      <Pill label={formatStatusLabel(session.status, locale)} tone={getStatusTone(session.status)} />
      <Pill
        label={session.visibility === 'private' ? copy({ de: 'Privat', en: 'Private', pl: 'Prywatny' }) : copy({ de: 'Öffentlich', en: 'Public', pl: 'Publiczny' })}
        tone={{ backgroundColor: '#f8fafc', borderColor: '#cbd5e1', textColor: '#475569' }}
      />
      <ProgressPill duel={duel} locale={locale} session={session} />
      {(duel.isSpectating || duel.spectatorCount > 0) ? (
        <Pill
          label={copy({ de: `Zuschauer ${duel.spectatorCount}`, en: `Audience ${duel.spectatorCount}`, pl: `Widownia ${duel.spectatorCount}` })}
          tone={{ backgroundColor: '#f5f3ff', borderColor: '#ddd6fe', textColor: '#6d28d9' }}
        />
      ) : null}
      {session.series ? (
        <Pill label={formatSeriesTitle(session.series, locale)} tone={{ backgroundColor: '#f5f3ff', borderColor: '#ddd6fe', textColor: '#6d28d9' }} />
      ) : null}
    </View>
  );
}

function SpectatorMessage({ copy, isAuthenticated }: { copy: DuelCopy, isAuthenticated: boolean }): React.JSX.Element {
  return (
    <MessageCard
