import type { Href } from 'expo-router';

type CreateKangurDuelsHrefOptions = {
  joinSessionId?: string | null;
  sessionId?: string | null;
  spectate?: boolean;
};

export const createKangurDuelsHref = (
  options: CreateKangurDuelsHrefOptions = {},
): Href => {
  const joinSessionId = options.joinSessionId?.trim() ?? '';
  const sessionId = options.sessionId?.trim() ?? '';
  const spectate = options.spectate === true;

  if (sessionId) {
    return ({
      pathname: '/duels',
      params: {
        sessionId,
        ...(spectate ? { spectate: '1' } : {}),
      },
    }) as unknown as Href;
  }

  if (joinSessionId) {
    return ({
      pathname: '/duels',
      params: {
        join: joinSessionId,
      },
    }) as unknown as Href;
  }

  return '/duels' as Href;
};

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { formatKangurMobileScoreDateTime } from '../scores/mobileScoreSummary';
import { type UseKangurMobileDuelSessionResult as DuelSessionState } from './useKangurMobileDuelSession';
import {
  isWaitingSessionStatus,
  resolveRoundProgress,
} from './utils/duels-ui';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

function getInviteeName(duel: DuelSessionState, copy: DuelCopy): string {
  const rawInviteeName = duel.session?.invitedLearnerName?.trim();
  if (typeof rawInviteeName === 'string' && rawInviteeName !== '') {
    return rawInviteeName;
  }
  return copy({
    de: 'der zweiten Person',
    en: 'the other player',
    pl: 'drugiej osoby',
  });
}

function getSessionTimelineItems(
  duel: DuelSessionState,
  copy: DuelCopy,
  locale: DuelLocale,
): string[] {
  const items: string[] = [];
  if (duel.session === null) {
    return items;
  }

  items.push(
    copy({
      de: `Erstellt ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
      en: `Created ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
      pl: `Utworzono ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
    }),
  );
  if (duel.session.startedAt !== null) {
    items.push(
      copy({
        de: `Gestartet ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
        en: `Started ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
        pl: `Rozpoczęto ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
      }),
    );
  }
  items.push(
    copy({
      de: `Zuletzt aktualisiert ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
      en: `Last updated ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
      pl: `Ostatnia aktualizacja ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
    }),
  );
  if (duel.session.endedAt !== null) {
    items.push(
      copy({
        de: `Beendet ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
        en: `Ended ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
        pl: `Zakończenie ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
      }),
    );
  }
  return items;
}

export function useKangurDuelsSessionState(
  copy: DuelCopy,
  locale: DuelLocale,
  duel: DuelSessionState,
): {
  activePlayersCount: number;
  canShareInvite: boolean;
  hasPendingInvitedPlayer: boolean;
  hasWaitingSession: boolean;
  inviteeName: string;
  isFinishedSession: boolean;
  isInvitedLearnerMissing: boolean;
  needsMorePlayersToStart: boolean;
  roundProgress: {
    total: number;
    completed: number;
    percentage: number;
  } | null;
  sessionTimelineItems: string[];
} {
  const hasWaitingSession = duel.session !== null && isWaitingSessionStatus(duel.session.status);
  const isFinishedSession = duel.session !== null && (duel.session.status === 'completed' || duel.session.status === 'aborted');
  const roundProgress = duel.session !== null
    ? resolveRoundProgress(duel.session, duel.player, duel.isSpectating)
    : null;
  const activePlayersCount =
    duel.session?.players.filter((player) => player.status !== 'left').length ?? 0;
  const hasPendingInvitedPlayer =
    duel.session?.players.some((player) => player.status === 'invited') ?? false;

  let isInvitedLearnerMissing = false;
  if (duel.session?.invitedLearnerId !== null && duel.session?.invitedLearnerId !== undefined) {
    const invitedId = duel.session.invitedLearnerId;
    isInvitedLearnerMissing = !duel.session.players.some(
      (p) => p.learnerId === invitedId && p.status !== 'left',
    );
  }

  const needsMorePlayersToStart = duel.session !== null && activePlayersCount < (duel.session.minPlayersToStart ?? 2);
  const canShareInvite = Boolean(
    duel.session !== null &&
      duel.player !== null &&
      !duel.isSpectating &&
      duel.session.visibility === 'private' &&
      hasWaitingSession &&
      (hasPendingInvitedPlayer || isInvitedLearnerMissing || needsMorePlayersToStart),
  );

  return {
    activePlayersCount,
    canShareInvite,
    hasPendingInvitedPlayer,
    hasWaitingSession,
    inviteeName: getInviteeName(duel, copy),
    isFinishedSession,
    isInvitedLearnerMissing,
    needsMorePlayersToStart,
    roundProgress,
    sessionTimelineItems: getSessionTimelineItems(duel, copy, locale),
  };
}

import type { KangurDuelLobbyChatListResponse, KangurDuelLobbyChatMessage } from '@kangur/contracts/kangur-duels-chat';
import { KANGUR_DUELS_LOBBY_CHAT_DEFAULT_LIMIT, KANGUR_DUELS_LOBBY_CHAT_MAX_MESSAGE_LENGTH } from '@kangur/contracts/kangur-duels-chat';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import {
  useKangurMobileI18n,
} from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { resolveMobileDuelErrorMessage } from './mobileDuelErrorMessages';

const MOBILE_DUEL_CHAT_POLL_MS = 12_000;

export type UseKangurMobileDuelLobbyChatResult = {
  error: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  isSending: boolean;
  maxMessageLength: number;
  messages: KangurDuelLobbyChatMessage[];
  refresh: () => Promise<void>;
  sendMessage: (message: string) => Promise<boolean>;
};

const appendMessage = (
  current: KangurDuelLobbyChatListResponse | undefined,
  incoming: KangurDuelLobbyChatMessage,
): KangurDuelLobbyChatListResponse => {
  const existingMessages = current?.messages ?? [];
  const deduped = existingMessages.filter((message) => message.id !== incoming.id);

  return {
    messages: [...deduped, incoming].sort((left, right) =>
      left.createdAt.localeCompare(right.createdAt),
    ),
    nextCursor: current?.nextCursor ?? null,
    serverTime: current?.serverTime ?? incoming.createdAt,
  };
};

export const useKangurMobileDuelLobbyChat =
  (): UseKangurMobileDuelLobbyChatResult => {
    const { copy } = useKangurMobileI18n();
    const queryClient = useQueryClient();
    const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
    const { isLoadingAuth, session } = useKangurMobileAuth();
    const [isSending, setIsSending] = useState(false);
    const learnerIdentity =
      session.user?.activeLearner?.id ??
      session.user?.email ??
      session.user?.id ??
      'guest';
    const isAuthenticated = session.status === 'authenticated';
    const isRestoringAuth = isLoadingAuth && !isAuthenticated;
    const queryKey = [
      'kangur-mobile',
      'duels',
      'lobby-chat',
      apiBaseUrl,
      learnerIdentity,
    ] as const;

    const chatQuery = useQuery({
      enabled: isAuthenticated,
      queryKey,
      queryFn: async () =>
        apiClient.listDuelLobbyChat(
          { limit: KANGUR_DUELS_LOBBY_CHAT_DEFAULT_LIMIT },
          { cache: 'no-store' },
        ),
      refetchInterval: MOBILE_DUEL_CHAT_POLL_MS,
      staleTime: 8_000,
    });

    return {
      error: resolveMobileDuelErrorMessage({
        error: chatQuery.error,
        copy,
        fallback: {
          de: 'Der Lobby-Chat konnte nicht geladen werden.',
          en: 'Could not load the lobby chat.',
          pl: 'Nie udało się pobrać czatu lobby.',
        },
        unauthorized: {
          de: 'Melde dich an, um den Lobby-Chat zu nutzen.',
          en: 'Sign in to use the lobby chat.',
          pl: 'Zaloguj się, aby korzystać z czatu lobby.',
        },
        unauthorizedStatuses: [401, 403],
      }),
      isAuthenticated,
      isLoading: isRestoringAuth || chatQuery.isLoading,
      isRestoringAuth,
      isSending,
      maxMessageLength: KANGUR_DUELS_LOBBY_CHAT_MAX_MESSAGE_LENGTH,
      messages: chatQuery.data?.messages ?? [],
      refresh: async () => {
        await chatQuery.refetch();
      },
      sendMessage: async (message) => {
        const trimmed = message.trim();
        if (!trimmed) {
          return false;
        }

        setIsSending(true);

        try {
          const response = await apiClient.sendDuelLobbyChatMessage(
            {
              message: trimmed,
            },
            { cache: 'no-store' },
          );

          queryClient.setQueryData<KangurDuelLobbyChatListResponse>(queryKey, (current) =>
            appendMessage(current, response.message),
          );

          return true;
        } catch {
          await chatQuery.refetch();
          return false;
        } finally {
          setIsSending(false);
        }
      },
    };
  };

import {
  type KangurMobileLocalizedValue,
} from '../i18n/kangurMobileI18n';

export const readSessionErrorStatus = (error: unknown): number | null => {
  if (typeof error !== 'object' || !error || !('status' in error)) {
    return null;
  }

  return typeof (error as { status?: unknown }).status === 'number'
    ? ((error as { status: number }).status)
    : null;
};

export const readSessionErrorMessage = (error: unknown): string | null => {
  if (!(error instanceof Error)) {
    return null;
  }

  const message = error.message.trim();
  return message.length > 0 ? message : null;
};

export const isFallbackSessionErrorMessage = (message: string): boolean => {
  const normalized = message.toLowerCase();
  return normalized === 'failed to fetch' || normalized.includes('networkerror');
};

export const getUnauthorizedSessionErrorMessage = (
  copy: (value: KangurMobileLocalizedValue<string>) => string,
): string =>
  copy({
    de: 'Melde dich an, um dieses Duell zu öffnen.',
    en: 'Sign in to open this duel.',
    pl: 'Zaloguj się, aby otworzyć ten pojedynek.',
  });

export const resolveSessionMessageWithFallback = (
  message: string | null,
  fallback: string,
): string => {
  if (!message || isFallbackSessionErrorMessage(message)) {
    return fallback;
  }

  return message;
};

export const toSessionErrorMessage = (
  error: unknown,
  fallback: string,
  copy: (value: KangurMobileLocalizedValue<string>) => string,
): string | null => {
  if (!error) {
    return null;
  }

  if (readSessionErrorStatus(error) === 401) {
    return getUnauthorizedSessionErrorMessage(copy);
  }

  return resolveSessionMessageWithFallback(readSessionErrorMessage(error), fallback);
};

import type {
  KangurDuelChoice,
  KangurDuelPlayer,
  KangurDuelQuestion,
  KangurDuelSession,
} from '@kangur/contracts/kangur-duels';

export const resolveCurrentQuestionIndex = (
  duelSession: KangurDuelSession | null,
  isSpectating: boolean,
  player: KangurDuelPlayer | null,
): number | null => {
  if (!duelSession) {
    return null;
  }

  const currentQuestionIndex = isSpectating
    ? duelSession.currentQuestionIndex ?? 0
    : player?.currentQuestionIndex ?? 0;

  return currentQuestionIndex >= duelSession.questionCount
    ? null
    : currentQuestionIndex;
};

export const resolveCurrentQuestion = (
  duelSession: KangurDuelSession | null,
  isSpectating: boolean,
  player: KangurDuelPlayer | null,
): KangurDuelQuestion | null => {
  const currentQuestionIndex = resolveCurrentQuestionIndex(
    duelSession,
    isSpectating,
    player,
  );

  if (!duelSession || currentQuestionIndex === null) {
    return null;
  }

  return duelSession.questions[currentQuestionIndex] ?? null;
};

